const ANTHROPIC_UPSTREAM_MODEL_IDS = upstreamIdMap(ANTHROPIC_MODELS);
const OPENAI_UPSTREAM_MODEL_IDS = upstreamIdMap(OPENAI_MODELS);
const ANTHROPIC_UPSTREAM_ALIASES = aliasMap(ANTHROPIC_MODELS);
const OPENAI_UPSTREAM_ALIASES = aliasMap(OPENAI_MODELS);
const ANTHROPIC_EFFORT_OVERRIDES: Record<string, string> = {
  "eu.anthropic.claude-opus-4-7": "medium",
  "eu.anthropic.claude-opus-4-8": "medium",
};
const OPENAI_REASONING_SUMMARY_DISABLED = new Set(["o4-mini-2025-04-16"]);

const streamSimpleAnthropic = anthropicMessagesApi().streamSimple;
const streamSimpleOpenAIResponses = openAIResponsesApi().streamSimple;
const gatewayHeaders = { Authorization: `Bearer ${AUTH_TOKEN_REF}` };
const imageTextInput: ModelInput[] = ["text", "image"];

function upstreamIdMap(
  models: readonly GatewayModelSpec[],
): Record<string, string> {
  return Object.fromEntries(
    models.map(({ id, upstreamId }) => [id, upstreamId]),
  );
}

function aliasMap(models: readonly GatewayModelSpec[]): Record<string, string> {
  const entries = models.flatMap(({ upstreamId, aliases = [] }) =>
    [upstreamId, ...aliases].map((alias) => [alias.toLowerCase(), upstreamId]),
  );
  return Object.fromEntries(entries);
}

function isGatewayModel(model: Model<Api>, legoProvider: string): boolean {
  return (
    model.provider === legoProvider ||
    (typeof model.baseUrl === "string" &&
      model.baseUrl.startsWith(GATEWAY_ROOT_URL))
  );
}

function resolveUpstreamId(
  modelId: string,
  friendlyMap: Record<string, string>,
  aliases: Record<string, string>,
): string {
  return friendlyMap[modelId] ?? aliases[modelId.toLowerCase()] ?? modelId;
}

function payloadObject(payload: unknown): JsonObject {
  return payload && typeof payload === "object" && !Array.isArray(payload)
    ? (payload as JsonObject)
    : {};
}

function applyLegoAnthropicPayloadRequirements(
  payload: unknown,
  upstreamModelId: string,
  effortOverride?: string,
): JsonObject {
  const patched = payloadObject(payload);
  patched.model = upstreamModelId;
  patched.temperature = 1;

  if (effortOverride) {
    patched.output_config = {
      ...payloadObject(patched.output_config),
      effort: effortOverride,
    };
  }

  return patched;
}

function applyLegoOpenAIPayloadRequirements(
  payload: unknown,
  context: Context,
  upstreamModelId: string,
): JsonObject {
  let patched = payloadObject(payload);
  patched.model = upstreamModelId;
  patched.store = true;
  if (
    OPENAI_REASONING_SUMMARY_DISABLED.has(upstreamModelId) &&
    payloadObject(patched.reasoning).summary
  ) {
    patched.reasoning = {
      ...payloadObject(patched.reasoning),
      summary: undefined,
    };
  }

  const continuation = getTailToolContinuation(context);
  if (!continuation || !Array.isArray(patched.input)) return patched;

  const functionOutputs = patched.input
    .filter((item: any) => item?.type === "function_call_output")
    .slice(-continuation.toolResultCount);

  if (functionOutputs.length !== continuation.toolResultCount) return patched;

  patched = {
    ...patched,
    previous_response_id: continuation.previousResponseId,
    input: functionOutputs,
  };

  return patched;
}

function patchGatewayRequestBody(url: string, body: string): string {
  try {
    const payload = JSON.parse(body);
    if (
      !payload ||
      typeof payload !== "object" ||
      typeof payload.model !== "string"
    )
      return body;

    if (url.includes("/anthropic/")) {
      const upstreamId = resolveUpstreamId(
        payload.model,
        ANTHROPIC_UPSTREAM_MODEL_IDS,
        ANTHROPIC_UPSTREAM_ALIASES,
      );
      return JSON.stringify(
        applyLegoAnthropicPayloadRequirements(
          payload,
          upstreamId,
          ANTHROPIC_EFFORT_OVERRIDES[upstreamId],
        ),
      );
    }

    if (url.includes("/openai/")) {
      payload.model = resolveUpstreamId(
        payload.model,
        OPENAI_UPSTREAM_MODEL_IDS,
        OPENAI_UPSTREAM_ALIASES,
      );
      payload.store = true;
      return JSON.stringify(payload);
    }
  } catch {
    return body;
  }

  return body;
}

let gatewayFetchRewriteInstalled = false;
function installGatewayFetchRewrite(): void {
  if (gatewayFetchRewriteInstalled) return;
  gatewayFetchRewriteInstalled = true;

  const originalFetch = globalThis.fetch.bind(globalThis);

  globalThis.fetch = (async (input: any, init?: any) => {
    const url = typeof input === "string" ? input : (input?.url ?? "");
    if (
      typeof url === "string" &&
      url.startsWith(GATEWAY_ROOT_URL) &&
      typeof init?.body === "string"
    ) {
      init = { ...init, body: patchGatewayRequestBody(url, init.body) };
    }

    return originalFetch(input, init);
  }) as typeof globalThis.fetch;
}

function getTailToolContinuation(
  context: Context,
): { previousResponseId: string; toolResultCount: number } | undefined {
  const messages = context.messages;
  let index = messages.length - 1;
  let toolResultCount = 0;

  while (index >= 0 && messages[index]?.role === "toolResult") {
    toolResultCount++;
    index--;
  }

  const assistant = messages[index];
  if (toolResultCount === 0 || assistant?.role !== "assistant")
    return undefined;
  if (
    typeof assistant.responseId !== "string" ||
    assistant.responseId.length === 0
  )
    return undefined;
  if (!assistant.content.some((block) => block.type === "toolCall"))
    return undefined;

  return { previousResponseId: assistant.responseId, toolResultCount };
}

function createErrorMessage(
  model: Model<Api>,
  error: unknown,
): AssistantMessage {
  return {
    role: "assistant",
    content: [],
    api: model.api,
    provider: model.provider,
    model: model.id,
    usage: {
      input: 0,
      output: 0,
      cacheRead: 0,
      cacheWrite: 0,
      totalTokens: 0,
      cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
    },
    stopReason: "error",
    errorMessage: error instanceof Error ? error.message : String(error),
    timestamp: Date.now(),
  };
}

function restoreAssistantIdentity(
  message: AssistantMessage | undefined,
  model: Model<Api>,
): void {
  if (!message) return;
  message.provider = model.provider;
  message.model = model.id;
}

function restoreEventIdentity(
  event: AssistantMessageEvent,
  model: Model<Api>,
): AssistantMessageEvent {
  if ("partial" in event) restoreAssistantIdentity(event.partial, model);
  if (event.type === "done") restoreAssistantIdentity(event.message, model);
  if (event.type === "error") restoreAssistantIdentity(event.error, model);
  return event;
}

function withRestoredOutputIdentity(
  source: AssistantMessageEventStream,
  model: Model<Api>,
): AssistantMessageEventStream {
  const stream = createAssistantMessageEventStream();

  void (async () => {
    let finalEventSeen = false;
    try {
      for await (const event of source) {
        finalEventSeen ||= event.type === "done" || event.type === "error";
        stream.push(restoreEventIdentity(event, model));
      }

      if (!finalEventSeen) {
        stream.push({
          type: "error",
          reason: "error",
          error: createErrorMessage(
            model,
            "Provider stream ended without a final assistant message.",
          ),
        });
      }
    } catch (error) {
      stream.push({
        type: "error",
        reason: "error",
        error: createErrorMessage(model, error),
      });
    } finally {
      stream.end();
    }
  })();

  return stream;
}

function streamLegoGatewayAnthropic(
  model: Model<Api>,
  context: Context,
  options?: SimpleStreamOptions,
): AssistantMessageEventStream {
  if (!isGatewayModel(model, LEGO_GATEWAY_ANTHROPIC_PROVIDER)) {
    return streamSimpleAnthropic(
      model as Model<"anthropic-messages">,
      context,
      options,
    );
  }

  const upstreamModelId = resolveUpstreamId(
    model.id,
    ANTHROPIC_UPSTREAM_MODEL_IDS,
    ANTHROPIC_UPSTREAM_ALIASES,
  );
  const effortOverride = ANTHROPIC_EFFORT_OVERRIDES[upstreamModelId];

  const patchedOptions: SimpleStreamOptions = {
    ...options,
    reasoning: options?.reasoning ?? (effortOverride ? "medium" : "low"),
    onPayload: async (payload: any, requestModel: Model<Api>) => {
      const patched = applyLegoAnthropicPayloadRequirements(
        payload,
        upstreamModelId,
        effortOverride,
      );
      const hooked =
        (await options?.onPayload?.(patched, requestModel)) ?? patched;
      return applyLegoAnthropicPayloadRequirements(
        hooked,
        upstreamModelId,
        effortOverride,
      );
    },
  };

  return streamSimpleAnthropic(
    model as Model<"anthropic-messages">,
    context,
    patchedOptions,
  );
}

function streamLegoGatewayOpenAI(
  model: Model<Api>,
  context: Context,
  options?: SimpleStreamOptions,
): AssistantMessageEventStream {
  if (!isGatewayModel(model, LEGO_GATEWAY_OPENAI_PROVIDER)) {
    return streamSimpleOpenAIResponses(
      model as Model<"openai-responses">,
      context,
      options,
    );
  }

  const upstreamModelId = resolveUpstreamId(
    model.id,
    OPENAI_UPSTREAM_MODEL_IDS,
    OPENAI_UPSTREAM_ALIASES,
  );
  const patchedOptions: SimpleStreamOptions = {
    ...options,
    onPayload: async (payload: any, requestModel: Model<Api>) => {
      const patched = applyLegoOpenAIPayloadRequirements(
        payload,
        context,
        upstreamModelId,
      );
      const hooked =
        (await options?.onPayload?.(patched, requestModel)) ?? patched;
      return applyLegoOpenAIPayloadRequirements(
        hooked,
        context,
        upstreamModelId,
      );
    },
  };

  return withRestoredOutputIdentity(
    streamSimpleOpenAIResponses(
      {
        ...model,
        id: upstreamModelId,
        provider: "openai",
      } as Model<"openai-responses">,
      context,
      patchedOptions,
    ),
    model,
  );
}

const proxyCompat = {
  supportsEagerToolInputStreaming: false,
  supportsLongCacheRetention: false,
  supportsCacheControlOnTools: false,
};

const adaptiveThinkingCompat = {
  ...proxyCompat,
  forceAdaptiveThinking: true,
};

const openaiResponsesCompat = {
  sendSessionIdHeader: false,
  supportsLongCacheRetention: false,
};

function createAnthropicModel(spec: AnthropicModelSpec) {
  const reasoning = spec.reasoning ?? true;
  return {
    id: spec.id,
    name: spec.id,
    reasoning,
    ...(reasoning
      ? { thinkingLevelMap: spec.thinkingLevelMap ?? THINKING_ALWAYS_ON }
      : {}),
    input: [...imageTextInput],
    cost: spec.cost,
    contextWindow: 200_000,
    maxTokens: spec.maxTokens ?? 32_000,
    compat:
      spec.adaptiveThinking === false ? proxyCompat : adaptiveThinkingCompat,
  };
}

function createOpenAIModel(spec: OpenAIModelSpec) {
  return {
    id: spec.id,
    name: spec.name,
    reasoning: spec.reasoning,
    ...(spec.reasoning
      ? { thinkingLevelMap: spec.thinkingLevelMap ?? GPT_5_THINKING }
      : {}),
    input: [...imageTextInput],
    cost: spec.cost,
    contextWindow: spec.contextWindow,
    maxTokens: spec.maxTokens,
    compat: openaiResponsesCompat,
  };
}

export default function (pi: ExtensionAPI) {
  installGatewayFetchRewrite();

  pi.registerProvider(LEGO_GATEWAY_ANTHROPIC_PROVIDER, {
    name: "LEGO Gateway Anthropic",
    baseUrl: ANTHROPIC_BASE_URL,
    apiKey: AUTH_TOKEN_REF,
    authHeader: true,
    api: "anthropic-messages",
    headers: gatewayHeaders,
    streamSimple: streamLegoGatewayAnthropic,
    models: ANTHROPIC_MODELS.map(createAnthropicModel),
  });

  pi.registerProvider(LEGO_GATEWAY_OPENAI_PROVIDER, {
    name: "LEGO Gateway OpenAI",
    baseUrl: OPENAI_BASE_URL,
    apiKey: AUTH_TOKEN_REF,
    authHeader: true,
    api: "openai-responses",
    headers: gatewayHeaders,
    streamSimple: streamLegoGatewayOpenAI,
    models: OPENAI_MODELS.map(createOpenAIModel),
  });

  pi.registerCommand("lego-model-gateway", {
    description: "Show LEGO AI Model Gateway provider setup/status",
    handler: async (_args, ctx) => {
      const token = process.env[AUTH_TOKEN_ENV];
      const lines = [
        "LEGO AI Model Gateway providers registered:",
        `- ${LEGO_GATEWAY_ANTHROPIC_PROVIDER}: ${ANTHROPIC_BASE_URL}`,
        `- ${LEGO_GATEWAY_OPENAI_PROVIDER}: ${OPENAI_BASE_URL}`,
        `Gateway auth token env var: ${AUTH_TOKEN_ENV} ${token ? "is set" : "is NOT set"}`,
        "",
        "Anthropic model ID mapping:",
        ...Object.entries(ANTHROPIC_UPSTREAM_MODEL_IDS).map(
          ([label, upstreamId]) =>
            `- ${LEGO_GATEWAY_ANTHROPIC_PROVIDER}/${label} → ${upstreamId}`,
        ),
        "",
        "OpenAI model ID mapping:",
        ...Object.entries(OPENAI_UPSTREAM_MODEL_IDS).map(
          ([label, upstreamId]) =>
            `- ${LEGO_GATEWAY_OPENAI_PROVIDER}/${label} → ${upstreamId}`,
        ),
        "",
        "Select a model with /model or start pi with --model '<provider>/<model name>'.",
      ];
      ctx.ui.notify(lines.join("\n"), token ? "info" : "warning");
    },
  });
}

