const ANTHROPIC_UPSTREAM_MODEL_IDS = upstreamIdMap(ANTHROPIC_MODELS);
const OPENAI_UPSTREAM_MODEL_IDS = upstreamIdMap(OPENAI_MODELS);
const ANTHROPIC_UPSTREAM_ALIASES = aliasMap(ANTHROPIC_MODELS);
const OPENAI_UPSTREAM_ALIASES = aliasMap(OPENAI_MODELS);
const ANTHROPIC_EFFORT_OVERRIDES: Record<string, string> = {
  "eu.anthropic.claude-opus-4-7": "medium",
  "eu.anthropic.claude-opus-4-8": "medium",
};
const OPENAI_REASONING_SUMMARY_DISABLED = new Set(["o4-mini-2025-04-16"]);

const streamSimpleAnthropic = anthropicMessagesApi().streamSimple;
const streamSimpleOpenAIResponses = openAIResponsesApi().streamSimple;
const gatewayHeaders = { Authorization: `Bearer ${AUTH_TOKEN_REF}` };
const imageTextInput: ModelInput[] = ["text", "image"];

function upstreamIdMap(
  models: readonly GatewayModelSpec[],
): Record<string, string> {
  return Object.fromEntries(
    models.map(({ id, upstreamId }) => [id, upstreamId]),
  );
}

function aliasMap(models: readonly GatewayModelSpec[]): Record<string, string> {
  const entries = models.flatMap(({ upstreamId, aliases = [] }) =>
    [upstreamId, ...aliases].map((alias) => [alias.toLowerCase(), upstreamId]),
  );
  return Object.fromEntries(entries);
}

function isGatewayModel(model: Model<Api>, legoProvider: string): boolean {
  return (
    model.provider === legoProvider ||
    (typeof model.baseUrl === "string" &&
      model.baseUrl.startsWith(GATEWAY_ROOT_URL))
  );
}

function resolveUpstreamId(
  modelId: string,
  friendlyMap: Record<string, string>,
  aliases: Record<string, string>,
): string {
  return friendlyMap[modelId] ?? aliases[modelId.toLowerCase()] ?? modelId;
}

function payloadObject(payload: unknown): JsonObject {
  return payload && typeof payload === "object" && !Array.isArray(payload)
    ? (payload as JsonObject)
    : {};
}

function applyLegoAnthropicPayloadRequirements(
  payload: unknown,
  upstreamModelId: string,
  effortOverride?: string,
): JsonObject {
  const patched = payloadObject(payload);
  patched.model = upstreamModelId;
  patched.temperature = 1;

  if (effortOverride) {
    patched.output_config = {
      ...payloadObject(patched.output_config),
      effort: effortOverride,
    };
  }

  return patched;
}

function applyLegoOpenAIPayloadRequirements(
  payload: unknown,
  context: Context,
  upstreamModelId: string,
): JsonObject {
  let patched = payloadObject(payload);
  patched.model = upstreamModelId;
  patched.store = true;
  if (
    OPENAI_REASONING_SUMMARY_DISABLED.has(upstreamModelId) &&
    payloadObject(patched.reasoning).summary
  ) {
    patched.reasoning = {
      ...payloadObject(patched.reasoning),
      summary: undefined,
    };
  }

  const continuation = getTailToolContinuation(context);
  if (!continuation || !Array.isArray(patched.input)) return patched;

  const functionOutputs = patched.input
    .filter((item: any) => item?.type === "function_call_output")
    .slice(-continuation.toolResultCount);

  if (functionOutputs.length !== continuation.toolResultCount) return patched;

  patched = {
    ...patched,
    previous_response_id: continuation.previousResponseId,
    input: functionOutputs,
  };

  return patched;
}

function patchGatewayRequestBody(url: string, body: string): string {
  try {
    const payload = JSON.parse(body);
    if (
      !payload ||
      typeof payload !== "object" ||
      typeof payload.model !== "string"
    )
      return body;

    if (url.includes("/anthropic/")) {
      const upstreamId = resolveUpstreamId(
        payload.model,
        ANTHROPIC_UPSTREAM_MODEL_IDS,
        ANTHROPIC_UPSTREAM_ALIASES,
      );
      return JSON.stringify(
        applyLegoAnthropicPayloadRequirements(
          payload,
          upstreamId,
          ANTHROPIC_EFFORT_OVERRIDES[upstreamId],
        ),
      );
    }

    if (url.includes("/openai/")) {
      payload.model = resolveUpstreamId(
        payload.model,
        OPENAI_UPSTREAM_MODEL_IDS,
        OPENAI_UPSTREAM_ALIASES,
      );
      payload.store = true;
      return JSON.stringify(payload);
    }
  } catch {
    return body;
  }

  return body;
}

let gatewayFetchRewriteInstalled = false;
function installGatewayFetchRewrite(): void {
  if (gatewayFetchRewriteInstalled) return;
  gatewayFetchRewriteInstalled = true;

  const originalFetch = globalThis.fetch.bind(globalThis);

  globalThis.fetch = (async (input: any, init?: any) => {
    const url = typeof input === "string" ? input : (input?.url ?? "");
    if (
      typeof url === "string" &&
      url.startsWith(GATEWAY_ROOT_URL) &&
      typeof init?.body === "string"
    ) {
      init = { ...init, body: patchGatewayRequestBody(url, init.body) };
    }

    return originalFetch(input, init);
  }) as typeof globalThis.fetch;
}

function getTailToolContinuation(
  context: Context,
): { previousResponseId: string; toolResultCount: number } | undefined {
  const messages = context.messages;
  let index = messages.length - 1;
  let toolResultCount = 0;

  while (index >= 0 && messages[index]?.role === "toolResult") {
    toolResultCount++;
    index--;
  }

  const assistant = messages[index];
  if (toolResultCount === 0 || assistant?.role !== "assistant")
    return undefined;
  if (
    typeof assistant.responseId !== "string" ||
    assistant.responseId.length === 0
  )
    return undefined;
  if (!assistant.content.some((block) => block.type === "toolCall"))
    return undefined;

  return { previousResponseId: assistant.responseId, toolResultCount };
}

function createErrorMessage(
  model: Model<Api>,
  error: unknown,
): AssistantMessage {
  return {
    role: "assistant",
    content: [],
    api: model.api,
    provider: model.provider,
    model: model.id,
    usage: {
      input: 0,
      output: 0,
      cacheRead: 0,
      cacheWrite: 0,
      totalTokens: 0,
      cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
    },
    stopReason: "error",
    errorMessage: error instanceof Error ? error.message : String(error),
    timestamp: Date.now(),
  };
}

function restoreAssistantIdentity(
  message: AssistantMessage | undefined,
  model: Model<Api>,
): void {
  if (!message) return;
  message.provider = model.provider;
  message.model = model.id;
}

function restoreEventIdentity(
  event: AssistantMessageEvent,
  model: Model<Api>,
): AssistantMessageEvent {
  if ("partial" in event) restoreAssistantIdentity(event.partial, model);
  if (event.type === "done") restoreAssistantIdentity(event.message, model);
  if (event.type === "error") restoreAssistantIdentity(event.error, model);
  return event;
}

function withRestoredOutputIdentity(
  source: AssistantMessageEventStream,
  model: Model<Api>,
): AssistantMessageEventStream {
  const stream = createAssistantMessageEventStream();

  void (async () => {
    let finalEventSeen = false;
    try {
      for await (const event of source) {
        finalEventSeen ||= event.type === "done" || event.type === "error";
        stream.push(restoreEventIdentity(event, model));
      }

      if (!finalEventSeen) {
        stream.push({
          type: "error",
          reason: "error",
          error: createErrorMessage(
            model,
            "Provider stream ended without a final assistant message.",
          ),
        });
      }
    } catch (error) {
      stream.push({
        type: "error",
        reason: "error",
        error: createErrorMessage(model, error),
      });
    } finally {
      stream.end();
    }
  })();

  return stream;
}

function streamLegoGatewayAnthropic(
  model: Model<Api>,
  context: Context,
  options?: SimpleStreamOptions,
): AssistantMessageEventStream {
  if (!isGatewayModel(model, LEGO_GATEWAY_ANTHROPIC_PROVIDER)) {
    return streamSimpleAnthropic(
      model as Model<"anthropic-messages">,
      context,
      options,
    );
  }

  const upstreamModelId = resolveUpstreamId(
    model.id,
    ANTHROPIC_UPSTREAM_MODEL_IDS,
    ANTHROPIC_UPSTREAM_ALIASES,
  );
  const effortOverride = ANTHROPIC_EFFORT_OVERRIDES[upstreamModelId];

  const patchedOptions: SimpleStreamOptions = {
    ...options,
    reasoning: options?.reasoning ?? (effortOverride ? "medium" : "low"),
    onPayload: async (payload: any, requestModel: Model<Api>) => {
      const patched = applyLegoAnthropicPayloadRequirements(
        payload,
        upstreamModelId,
        effortOverride,
      );
      const hooked =
        (await options?.onPayload?.(patched, requestModel)) ?? patched;
      return applyLegoAnthropicPayloadRequirements(
        hooked,
        upstreamModelId,
        effortOverride,
      );
    },
  };

  return streamSimpleAnthropic(
    model as Model<"anthropic-messages">,
    context,
    patchedOptions,
  );
}

function streamLegoGatewayOpenAI(
  model: Model<Api>,
  context: Context,
  options?: SimpleStreamOptions,
): AssistantMessageEventStream {
  if (!isGatewayModel(model, LEGO_GATEWAY_OPENAI_PROVIDER)) {
    return streamSimpleOpenAIResponses(
      model as Model<"openai-responses">,
      context,
      options,
    );
  }

  const upstreamModelId = resolveUpstreamId(
    model.id,
    OPENAI_UPSTREAM_MODEL_IDS,
    OPENAI_UPSTREAM_ALIASES,
  );
  const patchedOptions: SimpleStreamOptions = {
    ...options,
    onPayload: async (payload: any, requestModel: Model<Api>) => {
      const patched = applyLegoOpenAIPayloadRequirements(
        payload,
        context,
        upstreamModelId,
      );
      const hooked =
        (await options?.onPayload?.(patched, requestModel)) ?? patched;
      return applyLegoOpenAIPayloadRequirements(
        hooked,
        context,
        upstreamModelId,
      );
    },
  };

  return withRestoredOutputIdentity(
    streamSimpleOpenAIResponses(
      {
        ...model,
        id: upstreamModelId,
        provider: "openai",
      } as Model<"openai-responses">,
      context,
      patchedOptions,
    ),
    model,
  );
}

const proxyCompat = {
  supportsEagerToolInputStreaming: false,
  supportsLongCacheRetention: false,
  supportsCacheControlOnTools: false,
};

const adaptiveThinkingCompat = {
  ...proxyCompat,
  forceAdaptiveThinking: true,
};

const openaiResponsesCompat = {
  sendSessionIdHeader: false,
  supportsLongCacheRetention: false,
};

function createAnthropicModel(spec: AnthropicModelSpec) {
  const reasoning = spec.reasoning ?? true;
  return {
    id: spec.id,
    name: spec.id,
    reasoning,
    ...(reasoning
      ? { thinkingLevelMap: spec.thinkingLevelMap ?? THINKING_ALWAYS_ON }
      : {}),
    input: [...imageTextInput],
    cost: spec.cost,
    contextWindow: 200_000,
    maxTokens: spec.maxTokens ?? 32_000,
    compat:
      spec.adaptiveThinking === false ? proxyCompat : adaptiveThinkingCompat,
  };
}

function createOpenAIModel(spec: OpenAIModelSpec) {
  return {
    id: spec.id,
    name: spec.name,
    reasoning: spec.reasoning,
    ...(spec.reasoning
      ? { thinkingLevelMap: spec.thinkingLevelMap ?? GPT_5_THINKING }
      : {}),
    input: [...imageTextInput],
    cost: spec.cost,
    contextWindow: spec.contextWindow,
    maxTokens: spec.maxTokens,
    compat: openaiResponsesCompat,
  };
}

export default function (pi: ExtensionAPI) {
  installGatewayFetchRewrite();

  pi.registerProvider(LEGO_GATEWAY_ANTHROPIC_PROVIDER, {
    name: "LEGO Gateway Anthropic",
    baseUrl: ANTHROPIC_BASE_URL,
    apiKey: AUTH_TOKEN_REF,
    authHeader: true,
    api: "anthropic-messages",
    headers: gatewayHeaders,
    streamSimple: streamLegoGatewayAnthropic,
    models: ANTHROPIC_MODELS.map(createAnthropicModel),
  });

  pi.registerProvider(LEGO_GATEWAY_OPENAI_PROVIDER, {
    name: "LEGO Gateway OpenAI",
    baseUrl: OPENAI_BASE_URL,
    apiKey: AUTH_TOKEN_REF,
    authHeader: true,
    api: "openai-responses",
    headers: gatewayHeaders,
    streamSimple: streamLegoGatewayOpenAI,
    models: OPENAI_MODELS.map(createOpenAIModel),
  });

  pi.registerCommand("lego-model-gateway", {
    description: "Show LEGO AI Model Gateway provider setup/status",
    handler: async (_args, ctx) => {
      const token = process.env[AUTH_TOKEN_ENV];
      const lines = [
        "LEGO AI Model Gateway providers registered:",
        `- ${LEGO_GATEWAY_ANTHROPIC_PROVIDER}: ${ANTHROPIC_BASE_URL}`,
        `- ${LEGO_GATEWAY_OPENAI_PROVIDER}: ${OPENAI_BASE_URL}`,
        `Gateway auth token env var: ${AUTH_TOKEN_ENV} ${token ? "is set" : "is NOT set"}`,
        "",
        "Anthropic model ID mapping:",
        ...Object.entries(ANTHROPIC_UPSTREAM_MODEL_IDS).map(
          ([label, upstreamId]) =>
            `- ${LEGO_GATEWAY_ANTHROPIC_PROVIDER}/${label} → ${upstreamId}`,
        ),
        "",
        "OpenAI model ID mapping:",
        ...Object.entries(OPENAI_UPSTREAM_MODEL_IDS).map(
          ([label, upstreamId]) =>
            `- ${LEGO_GATEWAY_OPENAI_PROVIDER}/${label} → ${upstreamId}`,
        ),
        "",
        "Select a model with /model or start pi with --model '<provider>/<model name>'.",
      ];
      ctx.ui.notify(lines.join("\n"), token ? "info" : "warning");
    },
  });
}

// Model definitions (IDs, context windows, max tokens) are derived from the
// LEGO GenAI Model Proxy Service config. Keep them in sync with:
// https://github.com/LEGO/genai-model-proxy-service/blob/main/src/genai_model_proxy_service/conf.json
//   - contextWindow  <- models.limit_inputs
//   - maxTokens      <- models.limit_outputs

import {
	anthropicMessagesApi,
	createAssistantMessageEventStream,
	openAIResponsesApi,
	type Api,
	type AssistantMessage,
	type AssistantMessageEvent,
	type AssistantMessageEventStream,
	type Context,
	type Model,
	type SimpleStreamOptions,
} from "@earendil-works/pi-ai";

// pi 0.80.x removed the top-level streamSimpleAnthropic / streamSimpleOpenAIResponses
// named exports. Each API implementation is now obtained via a per-api factory
// (anthropicMessagesApi() / openAIResponsesApi()) that returns a ProviderStreams
// object exposing `stream` and `streamSimple`. Resolve the per-api streamSimple
// implementations once and alias them to the prior names so the wrappers below are
// unchanged.
const streamSimpleAnthropic = anthropicMessagesApi().streamSimple;
const streamSimpleOpenAIResponses = openAIResponsesApi().streamSimple;
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

/**
 * LEGO corporate model proxies for pi.
 *
 * Auth:
 *   export LEGO_MPS_AUTH_TOKEN="..."
 *
 * MPS = Model Proxy Service. The same token is used for all LEGO proxy providers.
 *
 * Base URLs are the bare proxy paths: pi's Anthropic SDK appends /v1/messages
 * and the OpenAI Responses path appends /responses, so neither URL includes a suffix.
 */

const MPS_ROOT_URL = "https://models.assistant.legogroup.io";
const ANTHROPIC_BASE_URL = `${MPS_ROOT_URL}/anthropic`;
const OPENAI_BASE_URL = `${MPS_ROOT_URL}/openai`;
const AUTH_TOKEN_ENV = "LEGO_MPS_AUTH_TOKEN";
const AUTH_TOKEN_REF = `$${AUTH_TOKEN_ENV}`;

const LEGO_ANTHROPIC_PROVIDER = "lego-anthropic";
const LEGO_OPENAI_PROVIDER = "lego-openai";

// pi registers each provider's custom `streamSimple` GLOBALLY, keyed by API type
// (not by provider). So this extension's anthropic-messages / openai-responses
// handlers can be handed requests belonging to OTHER providers (e.g. github-copilot
// Claude and GPT models, which use the same API types). Rewriting those foreign
// requests to MPS/Bedrock upstream ids makes the real provider reject them with
// HTTP 400 model_not_supported. Only apply LEGO rewrites to requests that actually
// target MPS: match this extension's own provider ids, or an MPS base URL.
function isMpsModel(model: Model<Api>, legoProvider: string): boolean {
	if (model.provider === legoProvider) return true;
	return typeof model.baseUrl === "string" && model.baseUrl.startsWith(MPS_ROOT_URL);
}

const ANTHROPIC_UPSTREAM_MODEL_IDS: Record<string, string> = {
	"Claude Opus 4.8": "anthropic.claude-opus-4-8",
	"Claude Opus 4.7": "anthropic.claude-opus-4-7",
	"Claude Opus 4.6": "anthropic.claude-opus-4-6-v1",
	"Claude Sonnet 4.6": "anthropic.claude-sonnet-4-6",
	"Claude Haiku 4.5": "anthropic.claude-haiku-4-5-20251001-v1:0",
};

const OPENAI_FRIENDLY_MODEL_ID = "GPT 5.5";
const OPENAI_UPSTREAM_MODEL_ID = "gpt-5.5-2026-04-24";
const OPENAI_UPSTREAM_MODEL_IDS: Record<string, string> = {
	[OPENAI_FRIENDLY_MODEL_ID]: OPENAI_UPSTREAM_MODEL_ID,
};

// pi resolves a model reference whose id does not exactly match a registered
// friendly id (e.g. a lowercase/dotted form like "claude-opus-4.8" or "gpt-5.5"
// typed in settings.json or on --model) to a "custom model id", passing the raw
// string straight through. Without a mapping that raw id reaches MPS verbatim and
// MPS rejects it with HTTP 406 {"detail":"Not found any available model"}. These
// alias tables map the common non-friendly spellings back to the correct upstream
// id so the friendly->upstream rewrite still happens on the custom-id path.
const ANTHROPIC_UPSTREAM_ALIASES: Record<string, string> = {
	"claude-opus-4.8": "anthropic.claude-opus-4-8",
	"claude-opus-4-8": "anthropic.claude-opus-4-8",
	"claude-opus-4.7": "anthropic.claude-opus-4-7",
	"claude-opus-4-7": "anthropic.claude-opus-4-7",
	"claude-opus-4.6": "anthropic.claude-opus-4-6-v1",
	"claude-opus-4-6": "anthropic.claude-opus-4-6-v1",
	"claude-sonnet-4.6": "anthropic.claude-sonnet-4-6",
	"claude-sonnet-4-6": "anthropic.claude-sonnet-4-6",
	"claude-haiku-4.5": "anthropic.claude-haiku-4-5-20251001-v1:0",
	"claude-haiku-4-5": "anthropic.claude-haiku-4-5-20251001-v1:0",
};

const OPENAI_UPSTREAM_ALIASES: Record<string, string> = {
	"gpt-5.5": OPENAI_UPSTREAM_MODEL_ID,
	"gpt5.5": OPENAI_UPSTREAM_MODEL_ID,
};

// Resolve a requested model id to its MPS upstream id. Order: exact friendly id,
// then case-insensitive alias, then any value that is already a known upstream id,
// otherwise pass through unchanged.
function resolveUpstreamId(
	modelId: string,
	friendlyMap: Record<string, string>,
	aliasMap: Record<string, string>,
): string {
	if (friendlyMap[modelId]) return friendlyMap[modelId];
	const lower = modelId.toLowerCase();
	if (aliasMap[lower]) return aliasMap[lower];
	if (Object.values(friendlyMap).includes(modelId)) return modelId;
	return modelId;
}

// Single fetch wrapper that normalises every outgoing MPS request body, so requests
// emitted outside this provider's streamSimple wrappers (e.g. pi's tool-call
// continuation, which uses the built-in api provider) still carry the correct
// upstream model id and required per-route fields. Installed once; idempotent.
let mpsFetchRewriteInstalled = false;
function installMpsFetchRewrite(): void {
	if (mpsFetchRewriteInstalled) return;
	mpsFetchRewriteInstalled = true;

	const originalFetch = globalThis.fetch.bind(globalThis);

	globalThis.fetch = (async (input: any, init?: any) => {
		const url = typeof input === "string" ? input : (input?.url ?? "");
		const body = init?.body;
		// Only touch MPS chat routes with a JSON string body; leave /account/models and
		// anything non-JSON (or Request-object bodies) untouched.
		if (
			typeof url === "string" &&
			url.startsWith(MPS_ROOT_URL) &&
			typeof body === "string" &&
			(url.includes("/anthropic/") || url.includes("/openai/"))
		) {
			try {
				const payload = JSON.parse(body);
				if (payload && typeof payload === "object" && typeof payload.model === "string") {
					if (url.includes("/anthropic/")) {
						const upstream = resolveUpstreamId(
							payload.model,
							ANTHROPIC_UPSTREAM_MODEL_IDS,
							ANTHROPIC_UPSTREAM_ALIASES,
						);
						payload.model = upstream;
						// Adaptive thinking on the MPS/Bedrock Anthropic route requires temperature=1.
						payload.temperature = 1;
						const effortOverride = ANTHROPIC_EFFORT_OVERRIDES[upstream];
						if (effortOverride) {
							payload.output_config = { ...asPayloadObject(payload.output_config), effort: effortOverride };
						}
					} else {
						payload.model = resolveUpstreamId(
							payload.model,
							OPENAI_UPSTREAM_MODEL_IDS,
							OPENAI_UPSTREAM_ALIASES,
						);
						// The Responses route needs server-side state for previous_response_id chains.
						payload.store = true;
					}
					init = { ...init, body: JSON.stringify(payload) };
				}
			} catch {
				// Non-JSON or unexpected shape: forward unchanged.
			}
		}
		return originalFetch(input, init);
	}) as typeof globalThis.fetch;
}

// LEGO MPS routes some Anthropic models through Bedrock adaptive thinking, where the
// deployed model only accepts a specific `output_config.effort`. pi (and its
// auto-compaction summarizer) can send other levels like "xhigh", which Bedrock
// rejects with HTTP 400 invalid_reasoning_effort. Clamp effort per backend model.
// See conf.json / anthropic_normalize.py in the genai-model-proxy-service repo.
const ANTHROPIC_EFFORT_OVERRIDES: Record<string, string> = {
	"anthropic.claude-opus-4-7": "medium",
	"anthropic.claude-opus-4-8": "medium",
};

type ThinkingLevelMap = Record<string, string | null>;

// MPS keeps extended thinking enabled; it does not support turning it off.
const THINKING_ALWAYS_ON: ThinkingLevelMap = { off: null };

// GPT 5.5 on MPS accepts reasoning effort "none" (disabled), "low", "medium",
// "high", and "xhigh"; it rejects "minimal" with an empty-body HTTP 400. pi
// resolves a thinking level not present in this map by passing the raw level
// string straight through as the effort (see openai-responses.js: the lookup
// falls back to `options.reasoningEffort`), so every pi level must be mapped
// explicitly. "minimal" is folded onto the nearest supported tier, "low".
const GPT_5_5_THINKING: ThinkingLevelMap = {
	off: "none",
	minimal: "low",
	low: "low",
	medium: "medium",
	high: "high",
	xhigh: "xhigh",
};

// Opus 4.7/4.8 only accept effort "medium" on MPS/Bedrock, so expose only that level
// in the UI. streamLegoAnthropic clamps the effort defensively for non-UI callers.
const MEDIUM_ONLY_THINKING: ThinkingLevelMap = {
	off: null,
	minimal: null,
	low: null,
	high: null,
	xhigh: null,
};

function getTailToolContinuation(context: Context):
	| { previousResponseId: string; toolResultCount: number }
	| undefined {
	const messages = context.messages;
	let index = messages.length - 1;
	let toolResultCount = 0;

	while (index >= 0 && messages[index]?.role === "toolResult") {
		toolResultCount++;
		index--;
	}
	if (toolResultCount === 0) return undefined;

	const assistant = messages[index];
	if (assistant?.role !== "assistant") return undefined;
	if (typeof assistant.responseId !== "string" || assistant.responseId.length === 0) return undefined;
	if (!assistant.content.some((block) => block.type === "toolCall")) return undefined;

	return { previousResponseId: assistant.responseId, toolResultCount };
}

function createErrorMessage(model: Model<any>, error: unknown): AssistantMessage {
	return {
		role: "assistant",
		content: [],
		api: model.api,
		provider: model.provider,
		model: model.id,
		usage: {
			input: 0,
			output: 0,
			cacheRead: 0,
			cacheWrite: 0,
			totalTokens: 0,
			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
		},
		stopReason: "error",
		errorMessage: error instanceof Error ? error.message : String(error),
		timestamp: Date.now(),
	};
}

function restoreAssistantIdentity(message: AssistantMessage | undefined, model: Model<any>): void {
	if (!message) return;
	message.provider = model.provider;
	message.model = model.id;
}

function restoreEventIdentity(event: AssistantMessageEvent, model: Model<any>): AssistantMessageEvent {
	if ("partial" in event) {
		restoreAssistantIdentity(event.partial, model);
	}
	if (event.type === "done") {
		restoreAssistantIdentity(event.message, model);
	} else if (event.type === "error") {
		restoreAssistantIdentity(event.error, model);
	}
	return event;
}

function withRestoredOutputIdentity(
	source: AssistantMessageEventStream,
	model: Model<any>,
): AssistantMessageEventStream {
	const stream = createAssistantMessageEventStream();

	(async () => {
		let finalEventSeen = false;
		try {
			for await (const event of source) {
				if (event.type === "done" || event.type === "error") finalEventSeen = true;
				stream.push(restoreEventIdentity(event, model));
			}
			if (!finalEventSeen) {
				stream.push({
					type: "error",
					reason: "error",
					error: createErrorMessage(model, "Provider stream ended without a final assistant message."),
				});
			}
		} catch (error) {
			stream.push({ type: "error", reason: "error", error: createErrorMessage(model, error) });
		} finally {
			// Always terminate the wrapped stream, including the throw path, so consumers
			// awaiting completion can never hang.
			stream.end();
		}
	})();

	return stream;
}

// MPS occasionally returns HTTP 406 `{"detail":"Not found any available model"}`
// (or, on the OpenAI route, a 406 with no body) when its backend deployment pool is
// momentarily out of capacity. This is a transient routing/capacity condition, not an
// account/model error: the same request succeeds moments later. pi treats the 406 as a
// terminal error and fails the provider over, so we retry the request a few times with
// jittered backoff before letting the error surface.
const MPS_406_MAX_ATTEMPTS = 3;
const MPS_406_BASE_DELAY_MS = 500;

function isRetryable406(event: AssistantMessageEvent): boolean {
	if (event.type !== "error") return false;
	const message = (event.error as AssistantMessage | undefined)?.errorMessage ?? "";
	return message.includes("406");
}

// Only safe to retry if nothing has streamed to the user yet; a 406 is a pre-stream
// routing rejection, so in practice no content precedes it, but guard anyway so a
// late failure can never duplicate already-emitted output.
function eventHasStreamedContent(event: AssistantMessageEvent): boolean {
	const message: any = event.type === "done" ? (event as any).message : (event as any).partial;
	const content = message?.content;
	if (!Array.isArray(content)) return false;
	return content.some(
		(block: any) =>
			(block?.type === "text" && block.text) ||
			(block?.type === "thinking" && block.thinking) ||
			block?.type === "toolCall",
	);
}

function delay(ms: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

// Wraps a stream factory (each call issues a fresh upstream request) and retries on a
// transient 406 before any content has streamed. On the final attempt the 406 is passed
// through unchanged so pi's normal failover still applies.
function withMps406Retry(
	makeSource: () => AssistantMessageEventStream,
	model: Model<any>,
	maxAttempts = MPS_406_MAX_ATTEMPTS,
): AssistantMessageEventStream {
	const out = createAssistantMessageEventStream();

	(async () => {
		try {
			for (let attempt = 1; ; attempt++) {
				const source = makeSource();
				let contentStarted = false;
				let finalEventSeen = false;
				let retrying = false;

				for await (const event of source) {
					if (eventHasStreamedContent(event)) contentStarted = true;

					if (isRetryable406(event) && !contentStarted && attempt < maxAttempts) {
						// Swallow the 406 and retry with exponential backoff + jitter.
						retrying = true;
						break;
					}

					if (event.type === "done" || event.type === "error") finalEventSeen = true;
					out.push(event);
				}

				if (retrying) {
					const backoff = MPS_406_BASE_DELAY_MS * 2 ** (attempt - 1) + Math.random() * MPS_406_BASE_DELAY_MS;
					await delay(backoff);
					continue;
				}

				if (!finalEventSeen) {
					out.push({
						type: "error",
						reason: "error",
						error: createErrorMessage(model, "Provider stream ended without a final assistant message."),
					});
				}
				break;
			}
		} catch (error) {
			out.push({ type: "error", reason: "error", error: createErrorMessage(model, error) });
		} finally {
			out.end();
		}
	})();

	return out;
}

function asPayloadObject(payload: any): Record<string, any> {
	return payload && typeof payload === "object" && !Array.isArray(payload) ? payload : {};
}

function applyLegoAnthropicPayloadRequirements(
	payload: any,
	upstreamModelId: string,
	effortOverride?: string,
): Record<string, any> {
	const patched = asPayloadObject(payload);

	// Keep pi's visible model ID friendly, but send MPS its required backend ID.
	patched.model = upstreamModelId;

	// LEGO MPS requires temperature=1 when Anthropic thinking is enabled.
	patched.temperature = 1;

	// Clamp adaptive-thinking effort to a value the backend model accepts. This also
	// covers internal pi calls (e.g. compaction summarization) that can request an
	// unsupported level the UI thinking selector would not.
	if (effortOverride) {
		const outputConfig = asPayloadObject(patched.output_config);
		patched.output_config = { ...outputConfig, effort: effortOverride };
	}

	return patched;
}

function applyLegoOpenAIPayloadRequirements(
	payload: any,
	context: Context,
	upstreamModelId: string,
): Record<string, any> {
	let patched = asPayloadObject(payload);

	// Keep pi's visible model ID friendly, but send MPS its required backend ID.
	patched.model = upstreamModelId;

	// LEGO's Responses proxy cannot resolve previous_response_id for responses
	// created with store:false. pi defaults to store:false, so this provider opts
	// into server-side response state to make tool continuations work.
	patched.store = true;

	const continuation = getTailToolContinuation(context);
	if (continuation) {
		const functionOutputs = Array.isArray(patched.input)
			? patched.input
					.filter((item: any) => item?.type === "function_call_output")
					.slice(-continuation.toolResultCount)
			: [];

		if (functionOutputs.length === continuation.toolResultCount) {
			patched = {
				...patched,
				previous_response_id: continuation.previousResponseId,
				input: functionOutputs,
			};
		}
	}

	return patched;
}

function streamLegoAnthropic(
	model: Model<Api>,
	context: Context,
	options?: SimpleStreamOptions,
): AssistantMessageEventStream {
	// Foreign providers (e.g. github-copilot) share the anthropic-messages API and can
	// be routed here; pass them straight to the unmodified built-in stream so their
	// model ids and payloads are never rewritten to MPS upstream ids.
	if (!isMpsModel(model, LEGO_ANTHROPIC_PROVIDER)) {
		return streamSimpleAnthropic(model as Model<"anthropic-messages">, context, options);
	}

	const upstreamModelId = resolveUpstreamId(model.id, ANTHROPIC_UPSTREAM_MODEL_IDS, ANTHROPIC_UPSTREAM_ALIASES);
	const effortOverride = ANTHROPIC_EFFORT_OVERRIDES[upstreamModelId];
	const reasoning = options?.reasoning ?? (effortOverride ? "medium" : "low");

	const patchedOptions: SimpleStreamOptions = {
		...options,
		reasoning,
		onPayload: async (payload: any, requestModel: Model<Api>) => {
			const patched = applyLegoAnthropicPayloadRequirements(payload, upstreamModelId, effortOverride);
			// Re-apply our invariants after any downstream hook so it cannot drop required fields.
			const hooked = (await options?.onPayload?.(patched, requestModel)) ?? patched;
			return applyLegoAnthropicPayloadRequirements(hooked, upstreamModelId, effortOverride);
		},
	};

	return withMps406Retry(
		() => streamSimpleAnthropic(model as Model<"anthropic-messages">, context, patchedOptions),
		model,
	);
}

function streamLegoOpenAI(
	model: Model<Api>,
	context: Context,
	options?: SimpleStreamOptions,
): AssistantMessageEventStream {
	// Foreign providers (e.g. github-copilot) share the openai-responses API and can be
	// routed here; pass them straight to the unmodified built-in stream so their model
	// ids and payloads are never rewritten to MPS upstream ids.
	if (!isMpsModel(model, LEGO_OPENAI_PROVIDER)) {
		return streamSimpleOpenAIResponses(model as Model<"openai-responses">, context, options);
	}

	const upstreamModelId = resolveUpstreamId(model.id, OPENAI_UPSTREAM_MODEL_IDS, OPENAI_UPSTREAM_ALIASES);

	const patchedOptions: SimpleStreamOptions = {
		...options,
		onPayload: async (payload: any, requestModel: Model<Api>) => {
			const patched = applyLegoOpenAIPayloadRequirements(payload, context, upstreamModelId);
			// Re-apply our invariants after any downstream hook so it cannot drop required fields.
			const hooked = (await options?.onPayload?.(patched, requestModel)) ?? patched;
			return applyLegoOpenAIPayloadRequirements(hooked, context, upstreamModelId);
		},
	};

	// pi's OpenAI Responses serializer preserves native Responses function_call
	// IDs only for providers named "openai", "openai-codex", or "opencode".
	// LEGO MPS is OpenAI-compatible, so stream through a temporary OpenAI alias.
	//
	// Each retry attempt issues a fresh request; the temporary alias must not leak into
	// the saved session, so identity is restored per attempt before the retry layer.
	return withMps406Retry(
		() =>
			withRestoredOutputIdentity(
				streamSimpleOpenAIResponses(
					{ ...model, id: upstreamModelId, provider: "openai" } as Model<"openai-responses">,
					context,
					patchedOptions,
				),
				model,
			),
		model,
	);
}

function getMpsModelLookupIds(model: any): string[] {
	const ids = new Set<string>();
	for (const value of [model?.name, model?.id]) {
		if (typeof value === "string" && value.length > 0) ids.add(value);
	}
	// MPS returns Azure/OpenAI deployments split as name + version; the request `model`
	// matches the joined, lowercased form (e.g. gpt-5.5 + 2026-04-24 -> gpt-5.5-2026-04-24).
	if (typeof model?.name === "string" && typeof model?.version === "string" && model.version.length > 0) {
		ids.add(`${model.name}-${model.version}`.toLowerCase());
	}
	return [...ids];
}

// Upstream model ids the account can use, in their label/name/id forms. A non-empty
// set is authoritative (even total revocation, which fails closed); an empty set means
// the probe failed or the body was ambiguous, so callers fail open.
//
// We deliberately do NOT cache this: availability is authorization state, and a stale
// cache could report a revoked model as available, reintroducing the exact 406 the
// filter exists to prevent. It is re-fetched on startup and on each diagnostic.
async function fetchAvailableModelIds(
	rootUrl: string,
	token: string,
	timeoutMs = AVAILABILITY_TIMEOUT_MS,
): Promise<Set<string>> {
	const controller = new AbortController();
	const timeout = setTimeout(() => controller.abort(), timeoutMs);
	try {
		const response = await fetch(`${rootUrl}/account/models`, {
			headers: { "api-key": token },
			signal: controller.signal,
		});
		if (!response.ok) {
			throw new Error(`${response.status} ${await response.text()}`);
		}
		const body = await response.json();
		return new Set<string>(Array.isArray(body) ? body.flatMap(getMpsModelLookupIds) : []);
	} finally {
		clearTimeout(timeout);
	}
}

function formatAvailabilityLine(label: string, upstreamId: string, available: ReadonlySet<string>): string {
	return `- ${label} → ${upstreamId}: ${available.has(upstreamId) ? "available" : "NOT available"}`;
}

function keepAvailableModel(
	model: { id: string },
	upstreamModelIds: Record<string, string>,
	availableModelIds: ReadonlySet<string>,
): boolean {
	if (availableModelIds.size === 0) return true;
	return availableModelIds.has(upstreamModelIds[model.id] ?? model.id);
}

// The availability probe blocks startup, so keep the bound short; the same bound is
// reused by the diagnostic command for consistency.
const AVAILABILITY_TIMEOUT_MS = 2_500;

const proxyCompat = {
	// Corporate gateways often reject pi's newest per-tool eager streaming field.
	// pi will fall back to the older fine-grained tool-streaming beta header.
	supportsEagerToolInputStreaming: false,

	// Avoid long-cache TTLs/tool cache markers unless the proxy explicitly supports them.
	supportsLongCacheRetention: false,
	supportsCacheControlOnTools: false,
};

const adaptiveThinkingCompat = {
	...proxyCompat,
	// MPS Anthropic routes use adaptive thinking when thinking is enabled.
	forceAdaptiveThinking: true,
};

const openaiResponsesCompat = {
	// Keep the proxy request conservative; enable these only if the gateway supports them.
	sendSessionIdHeader: false,
	supportsLongCacheRetention: false,
};

// Per-1M-token pricing, mirrored from the LEGO MPS / Anthropic published rates.
const OPUS_COST = { input: 5, output: 25, cacheRead: 0.5, cacheWrite: 6.25 };
const SONNET_COST = { input: 3, output: 15, cacheRead: 0.3, cacheWrite: 3.75 };
const HAIKU_COST = { input: 1, output: 5, cacheRead: 0.1, cacheWrite: 1.25 };

// All MPS Anthropic models share the same context window; only cost, max-output,
// and thinking mode differ. Most use adaptive thinking, but Haiku 4.5 rejects
// `output_config.effort` and must use budget-based thinking instead.
function anthropicModel(
	id: string,
	cost: { input: number; output: number; cacheRead: number; cacheWrite: number },
	overrides: { maxTokens?: number; thinkingLevelMap?: ThinkingLevelMap; adaptiveThinking?: boolean } = {},
) {
	return {
		id,
		name: id,
		reasoning: true,
		thinkingLevelMap: overrides.thinkingLevelMap ?? THINKING_ALWAYS_ON,
		input: ["text", "image"] as ("text" | "image")[],
		cost,
		contextWindow: 200_000,
		maxTokens: overrides.maxTokens ?? 128_000,
		compat: overrides.adaptiveThinking === false ? proxyCompat : adaptiveThinkingCompat,
	};
}

export default async function (pi: ExtensionAPI) {
	// pi 0.79.x issues a tool-call continuation request through a path that does NOT
	// go through this provider's streamSimple wrapper (the built-in api provider is
	// used instead), so the friendly model id reaches MPS unrewritten and MPS answers
	// HTTP 406 {"detail":"Not found any available model"}. The streamLego* onPayload
	// rewrite only covers the first request. To make every request correct regardless
	// of which internal path emits it, wrap fetch and normalise the outgoing body for
	// MPS endpoints: map the model id to its upstream id and enforce the per-route
	// invariants (Anthropic adaptive thinking needs temperature=1 and a clamped effort;
	// the OpenAI Responses route needs store=true). The rewrite is idempotent, so the
	// already-correct streamLego* path is unaffected.
	installMpsFetchRewrite();

	// MPS model access is token/account-specific. When possible, register only the
	// models this token can actually use, so /model does not offer guaranteed 406s.
	//
	// This probe blocks startup, so it uses a short timeout. On timeout/error we fail
	// open (empty set) and register the full static list rather than delay launch.
	//
	// Note: a model filtered out here (revoked/unavailable) that is also the configured
	// defaultModel or a resumed session's model will cause pi to fall back to another
	// model. That is preferable to selecting a model that is guaranteed to 406.
	let availableModelIds = new Set<string>();
	const startupToken = process.env[AUTH_TOKEN_ENV];
	if (startupToken) {
		try {
			availableModelIds = await fetchAvailableModelIds(MPS_ROOT_URL, startupToken);
		} catch {
			// fail open
		}
	}

	const anthropicModels = [
		anthropicModel("Claude Opus 4.8", OPUS_COST, { thinkingLevelMap: MEDIUM_ONLY_THINKING }),
		anthropicModel("Claude Opus 4.7", OPUS_COST, { thinkingLevelMap: MEDIUM_ONLY_THINKING }),
		anthropicModel("Claude Opus 4.6", OPUS_COST),
		anthropicModel("Claude Sonnet 4.6", SONNET_COST),
		anthropicModel("Claude Haiku 4.5", HAIKU_COST, { maxTokens: 64_000, adaptiveThinking: false }),
	].filter((model) => keepAvailableModel(model, ANTHROPIC_UPSTREAM_MODEL_IDS, availableModelIds));

	const openaiModels = [
		{
			id: OPENAI_FRIENDLY_MODEL_ID,
			name: "GPT 5.5 (2026-04-24)",
			reasoning: true,
			thinkingLevelMap: GPT_5_5_THINKING,
			input: ["text", "image"] as ("text" | "image")[],
			cost: { input: 5, output: 30, cacheRead: 0.5, cacheWrite: 0 },
			contextWindow: 1_050_000,
			maxTokens: 128_000,
			compat: openaiResponsesCompat,
		},
	].filter((model) => keepAvailableModel(model, OPENAI_UPSTREAM_MODEL_IDS, availableModelIds));

	pi.registerProvider(LEGO_ANTHROPIC_PROVIDER, {
		name: "LEGO Anthropic",
		baseUrl: ANTHROPIC_BASE_URL,
		apiKey: AUTH_TOKEN_REF,
		api: "anthropic-messages",
		headers: {
			// The LEGO proxy expects this header name.
			"api-key": AUTH_TOKEN_REF,
		},
		streamSimple: streamLegoAnthropic,
		models: anthropicModels,
	});

	pi.registerProvider(LEGO_OPENAI_PROVIDER, {
		name: "LEGO OpenAI",
		baseUrl: OPENAI_BASE_URL,
		apiKey: AUTH_TOKEN_REF,
		api: "openai-responses",
		headers: {
			// Same LEGO MPS token as the Anthropic route.
			"api-key": AUTH_TOKEN_REF,
		},
		streamSimple: streamLegoOpenAI,
		models: openaiModels,
	});

	pi.registerCommand("lego-model-proxies", {
		description: "Show LEGO model proxy provider setup/status",
		handler: async (_args, ctx) => {
			const token = process.env[AUTH_TOKEN_ENV];
			const lines = [
				"LEGO proxy providers registered:",
				`- lego-anthropic: ${ANTHROPIC_BASE_URL}`,
				`- lego-openai: ${OPENAI_BASE_URL}`,
				`MPS auth token env var: ${AUTH_TOKEN_ENV} ${token ? "is set" : "is NOT set"}`,
			];

			let level: "info" | "warning" = token ? "info" : "warning";
			if (token) {
				try {
					const modelIds = await fetchAvailableModelIds(MPS_ROOT_URL, token);
					lines.push("", "Configured model availability for this token:");
					for (const [label, upstreamId] of Object.entries(ANTHROPIC_UPSTREAM_MODEL_IDS)) {
						lines.push(formatAvailabilityLine(`lego-anthropic/${label}`, upstreamId, modelIds));
					}
					for (const [label, upstreamId] of Object.entries(OPENAI_UPSTREAM_MODEL_IDS)) {
						lines.push(formatAvailabilityLine(`lego-openai/${label}`, upstreamId, modelIds));
					}
				} catch (error) {
					level = "warning";
					lines.push("", `Could not fetch /account/models: ${error instanceof Error ? error.message : String(error)}`);
				}
			}

			lines.push("", "Select a model with /model or start pi with --model '<provider>/<model name>'.");
			ctx.ui.notify(lines.join("\n"), level);
		},
	});

	pi.on("session_start", (_event, ctx) => {
		if (ctx.hasUI) ctx.ui.setStatus("lego-model-proxies", "LEGO proxy models");
	});

	pi.on("session_shutdown", (_event, ctx) => {
		if (ctx.hasUI) ctx.ui.setStatus("lego-model-proxies", undefined);
	});
}

